previewCss:
.darma-loader-loading-io-23 {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 6px;
      height: 44px;
    }
    .darma-loader-loading-io-23 i {
      display: block;
      width: 8px;
      height: 44px;
      border-radius: 999px;
      background: linear-gradient(180deg, var(--loader-color, #22c55e), var(--loader-secondary-color, #bbf7d0));
      transform-origin: center bottom;
      animation: darma-loader-loading-io-23-barPulse 0.99s ease-in-out infinite;
    }
    .darma-loader-loading-io-23 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loading-io-23 i:nth-child(2) { animation-delay: 0.09s; }
.darma-loader-loading-io-23 i:nth-child(3) { animation-delay: 0.18s; }
.darma-loader-loading-io-23 i:nth-child(4) { animation-delay: 0.27s; }
.darma-loader-loading-io-23 i:nth-child(5) { animation-delay: 0.36s; }
.darma-loader-loading-io-23 i:nth-child(6) { animation-delay: 0.45s; }
    @keyframes darma-loader-loading-io-23-barPulse { 0%, 100% { opacity: .25; transform: scaleY(.5); } 45% { opacity: 1; transform: scaleY(1); } }

